/* figures / visuals */
.figure{margin:28px 0;border:1px solid var(--line);border-radius:12px;background:var(--panel);padding:18px;overflow:hidden}
.figure svg{display:block;width:100%;height:auto}
.figcap{font-size:12.5px;color:var(--muted);margin-top:13px;font-family:var(--mono);letter-spacing:.01em;line-height:1.5}
.figcap b{color:var(--accent)}
.hero-fig{margin:30px 0 4px;border:1px solid var(--line);border-radius:14px;overflow:hidden;background:#0a0e14}
.hero-fig svg{display:block;width:100%;height:auto}
.dossier .figure{margin:15px 0 4px}

footer{padding:40px 0 70px;color:var(--muted);font-size:13px}

